import React from "react"
import { Button } from "carbon-components-react"
import { Link } from "react-router-dom"

export default function AccountData() {
  return (
    <div className="account-form">
      <h2>Account</h2>
      <div className="account-data">
        <div className="account-field">Name</div>
        <div className="account-value-container">
          <div className="account-value">Joseph</div>
          {/* <Link to="/account/change-name">Change name</Link> */}
        </div>
        <div className="account-field">Email</div>
        <div className="account-value-container">
          <div className="account-value">Joseph@rolmo.app</div>
          {/* <Link to="/account/change-email">Change email</Link> */}
        </div>
        <div className="account-field">Password</div>
        <div className="account-value-container">
          <div className="account-value">********</div>
          <Link to="/account/change-password">Change password</Link>
        </div>

        <Button className="signout" kind="tertiary">
          Sign out
        </Button>
      </div>
    </div>
  )
}
