import React from "react"
import { useLocation, useHistory } from "react-router-dom"
import Footer from "../Components/Footer"
import Header from "../Components/Header"
import success from "../assets/images/success.png"
import failed from "../assets/images/failed.png"
import pending from "../assets/images/pending.png"
import { Button } from "carbon-components-react"

function useQuery() {
  return new URLSearchParams(useLocation().search)
}

export default function Payment() {
  const query = useQuery()
  const history = useHistory()
  const status = query.get("transaction_status")

  const hanldeToProfile = () => {
    history.push("/account")
  }

  return (
    <div className="payment">
      <Header />
      <div className="payment-content">
        {status === "success" ? (
          <div className="payment-success">
            <img src={success} alt="success" />
            <h3>Payment successful</h3>
            <p>You can find your purchases on your profile.</p>
            <Button className="to-profile" onClick={hanldeToProfile}>
              Go to profile
            </Button>
          </div>
        ) : status === "pending" ? (
          <div className="payment-pending">
            <img src={pending} alt="pending" />
            <h3>Payment Pending</h3>
            <p>We are currently confirming your payment.</p>
          </div>
        ) : (
          <div className="payment-failed">
            <img src={failed} alt="failed" />
            <h3>Payment Failed</h3>
            <p>Please review your payment details and try again.</p>
          </div>
        )}
      </div>
      <Footer />
    </div>
  )
}
