import React from "react"
import videojs from "video.js"

export default class VideoPlayer extends React.Component {
  componentDidMount() {
    // instantiate Video.js
    const onExitFullWindow = this.props.onExitFullWindow
    this.player = videojs(this.videoNode, this.props, function onPlayerReady() {
      const player = this

      var toggleWindow = player.controlBar.addChild("button", {
        text: "Exit full window",
        clickHandler: function (event) {
          onExitFullWindow()
          player.controls(false)
          player.exitFullWindow()
        }
      })

      toggleWindow.addClass("player-togle-window")
    })
  }

  // destroy player on unmount
  componentWillUnmount() {
    if (this.player) {
      this.player.dispose()
    }
  }

  componentDidUpdate() {
    if (this.props.isFullWindow) {
      this.player.controls(true)
    }
  }

  enterFullScreen = () => {
    this.player.enterFullWindow()
  }

  toogleMuted = (isMuted) => {
    this.player.muted(isMuted)
  }

  // wrap the player in a div with a `data-vjs-player` attribute
  // so videojs won't create additional wrapper in the DOM
  // see https://github.com/videojs/video.js/pull/3856
  render() {
    return (
      <div>
        <div data-vjs-player>
          <video
            ref={(node) => (this.videoNode = node)}
            className="video-js"
          ></video>
        </div>
      </div>
    )
  }
}
