import React from "react"
import { Accordion, AccordionItem } from "carbon-components-react"

const faqs = [
  {
    title: "What is Rolmo?",
    desc: `What is Rolmo?`
  },
  {
    title: "How much does Rolmo cost?",
    desc: `How much does Rolmo cost?`
  },
  {
    title: "Where can I enjoy Rolmo?",
    desc: `The app will soon be available on App Store and Google Play.`
  }
]

export default function Faq() {
  return (
    <div className="faq flex-center">
      <h2 className="faq-title">FAQ</h2>
      <Accordion>
        {faqs?.map((item, index) => (
          <AccordionItem key={index} title={item.title}>
            <p style={{ marginTop: 13 }}>{item.desc}</p>
          </AccordionItem>
        ))}
      </Accordion>
    </div>
  )
}
