import React, { useEffect, useState } from "react"
import { Button } from "carbon-components-react"
import { useHistory } from "react-router-dom"

const clientKey = "SB-Mid-client-99Yky9lQW9cogkyo"

export default function BuyAccess() {
  const history = useHistory()
  const [token, setToken] = useState()
  const [snap, setSnap] = useState()

  useEffect(() => {
    fetch("https://wprne.xyz//wp-json/midtrans/v1/token")
      .then((res) => res.json())
      .then((res) => {
        setToken(res)
      })
  }, [])

  useEffect(() => {
    const script = document.createElement("script")
    script.src = "https://app.sandbox.midtrans.com/snap/snap.js"
    document.body.appendChild(script)

    script.dataset.clientKey = clientKey

    script.onload = () => {
      if ("snap" in window) {
        const { snap } = window
        setSnap(snap)
      }
    }
  }, [])

  const handleBuy = () => {
    snap.pay(token, {
      onSuccess: function (result) {
        history.push("payment/?transaction_status=success")
      },

      onPending: function (result) {
        history.push("payment/?transaction_status=pending")
      },

      onError: function (result) {
        history.push("payment/?transaction_status=failed")
      }
    })
  }

  return (
    <div className="buy-access-container">
      <Button
        className="buy-access"
        disabled={!(token && snap)}
        onClick={handleBuy}
      >
        Buy Access
      </Button>
      <p>IDR 199,000 for 1 year</p>
    </div>
  )
}
