import React, { useState, useEffect, useRef } from "react"
import { Modal, Button, Form, Loading } from "carbon-components-react"

export default function SignIn() {
  const [openSignin, setOpenSignin] = useState(false)
  const [openSignup, setOpenSignup] = useState(false)
  const [isLoading, setIsLoading] = useState(false)
  const timerRef = useRef()

  const handleOpenSigninModal = () => {
    setOpenSignin(true)
    setIsLoading(true)
  }

  const handleCloseSigninModal = () => {
    setOpenSignin(false)
  }

  const handleSwitchToSignupModal = () => {
    setOpenSignin(false)
    setOpenSignup(true)
    setIsLoading(true)
  }

  const handleSwitchToSigninModal = () => {
    setOpenSignup(false)
    setOpenSignin(true)
    setIsLoading(true)
  }

  const handleCloseSignupModal = () => {
    setOpenSignup(false)
  }

  useEffect(() => {
    if (isLoading && !timerRef.current)
      timerRef.current = setTimeout(() => {
        setIsLoading(false)
        timerRef.current = null
      }, 1000)
  }, [isLoading])

  return (
    <div className="signin">
      <Modal
        open={openSignin}
        modalHeading=""
        passiveModal
        size="sm"
        hasForm={false}
        onRequestClose={handleCloseSigninModal}
      >
        <div className="signin-modal account-form">
          {isLoading ? (
            <div className="loading-spiner">
              <Loading
                description="Active loading indicator"
                withOverlay={false}
              />
              <p>Please wait</p>
            </div>
          ) : (
            <>
              <h4>Sign In</h4>
              <Form>
                <input placeholder="Email" />
                <input placeholder="Password" />
                <Button className="submit" type="submit">
                  Sign In
                </Button>
                <div className="to-signup">
                  Not registered?
                  <Button kind="ghost" onClick={handleSwitchToSignupModal}>
                    Sign up now
                  </Button>
                </div>
              </Form>
            </>
          )}
        </div>
      </Modal>

      <Modal
        open={openSignup}
        modalHeading=""
        passiveModal
        size="sm"
        hasForm={false}
        onRequestClose={handleCloseSignupModal}
      >
        <div className="signup-modal account-form">
          {isLoading ? (
            <div className="loading-spiner">
              <Loading
                description="Active loading indicator"
                withOverlay={false}
              />
              <p>Please wait</p>
            </div>
          ) : (
            <>
              <h4>Sign Up</h4>
              <Form>
                <input placeholder="Email" />
                <input placeholder="Password" />
                <input placeholder="Confirm password" />
                <div className="to-signin">
                  Already registered?
                  <Button kind="ghost" onClick={handleSwitchToSigninModal}>
                    Sign in
                  </Button>
                </div>
                <Button className="submit" type="submit">
                  Sign Up
                </Button>
              </Form>
            </>
          )}
        </div>
      </Modal>
      <Button
        className="signin-header"
        kind="ghost"
        onClick={handleOpenSigninModal}
      >
        Sign in
      </Button>
    </div>
  )
}
